#!moo verb dispatch_object_function --on "Thing" --dspec none
# pylint: disable=return-outside-function,undefined-variable,no-name-in-module

# Generated by moo/zil_import — Phase 7 OBJECT-FUNCTION dispatch.

"""
Route a verb invocation through the dobj/iobj's ACTION callback.

Called by the syntax-row action-chain runner BEFORE the V-* substrate
helper fires, and by ``d_apply``'s PRSI / PRSO stages.  Looks up
``obj.action`` (the routine name set by the OBJECT-FUNCTION declaration
in ZIL source) and invokes the matching combined-callback verb on the
object.  The callback's body is an ``if the_verb == "attack": ... elif
the_verb == "take": ...`` ladder emitted by
:meth:`moo.zil_import.translator.ZilTranslator.translate_object_function_combined`.

Returning truthy short-circuits the action chain (matches ZIL
OBJECT-FUNCTION returning T to block the default action).  Returning
False or None lets the chain continue to the substrate v_routine.

:param args: ``(obj, verb_name, prep, iobj, phase)`` — the
    action-chain snapshot.  ``phase`` is informational only
    (``"pre"`` / ``"PRSI"`` / ``"PRSO"``).
:returns: ``True`` to short-circuit, ``False`` to pass through.
"""

from moo.sdk import NoSuchPropertyError

obj = args[0] if len(args) > 0 else None
verb_name_arg = args[1] if len(args) > 1 else None
prep = args[2] if len(args) > 2 else None
iobj = args[3] if len(args) > 3 else None

if obj is None or verb_name_arg is None:
    return False
try:
    action = obj.get_property("action")
except NoSuchPropertyError:
    return False
if not action or not obj.has_verb(action):
    return False

# Two kinds of routine end up as an object's ACTION:
#
# 1. A VERB?-dispatching *combined callback* (emitted by
#    ``translate_object_function_combined``) — it switches on the verb atom
#    and reads it from ``args[0]``.  These MUST be passed
#    ``(verb_name, prep, iobj)``.
# 2. A *plain ZIL routine* used directly as an ACTION (e.g. USELESS:
#    ``<ROUTINE USELESS ("OPT" THING STRING)>``) — in ZIL these are invoked
#    with NO arguments and read the parsed verb/objects from globals.
#    Passing ``verb_name`` as ``args[0]`` corrupts the routine's first
#    parameter: USELESS read ``'examine'`` as its ``THING`` arg and crashed
#    in ``article()`` (``'str' object has no attribute 'flag'``).
#
# The combined-callback emitter always writes ``the_verb = args[0]`` as its
# first unpack line; a plain routine never does.  Use that as the
# discriminator and invoke plain routines bare so they hit their canonical
# (no-verb-arg) branch.
verb_is_callback = True
try:
    action_verb = obj.get_verb(action)
    verb_is_callback = "the_verb = args[0]" in (action_verb.code or "")
except Exception:  # pylint: disable=broad-except
    # Can't inspect the source — preserve the prior (callback) calling
    # convention, which is correct for the common case.
    verb_is_callback = True
if verb_is_callback:
    return obj.invoke_verb(action, verb_name_arg, prep, iobj)
return obj.invoke_verb(action)
